const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const { GraphQLError } = require('graphql');
const depthLimit = require('graphql-depth-limit');
const { createComplexityLimitRule } = require('graphql-validation-complexity');

// Mock database
const users = [
  { id: '1', name: 'Alice Johnson', email: 'alice@example.com' },
  { id: '2', name: 'Bob Smith', email: 'bob@example.com' },
  { id: '3', name: 'Charlie Brown', email: 'charlie@example.com' }
];

const posts = [
  { id: '1', title: 'GraphQL Best Practices', content: 'Security is crucial...', authorId: '1' },
  { id: '2', title: 'Node.js Performance', content: 'Optimize your code...', authorId: '2' },
  { id: '3', title: 'Apollo Server Guide', content: 'Building APIs...', authorId: '1' },
  { id: '4', title: 'Database Design', content: 'Normalization tips...', authorId: '3' }
];

const comments = [
  { id: '1', content: 'Great article!', postId: '1', authorId: '2' },
  { id: '2', content: 'Very helpful, thanks!', postId: '1', authorId: '3' },
  { id: '3', content: 'I disagree with point 2', postId: '2', authorId: '1' },
  { id: '4', content: 'Can you elaborate?', postId: '2', authorId: '3' },
  { id: '5', content: 'Excellent explanation', postId: '3', authorId: '2' }
];

const typeDefs = `#graphql
  type User {
    id: ID!
    name: String!
    email: String!
    posts: [Post!]!
    comments: [Comment!]!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: User!
    comments: [Comment!]!
  }

  type Comment {
    id: ID!
    content: String!
    post: Post!
    author: User!
  }

  type Query {
    user(id: ID!): User
    users(limit: Int = 10, offset: Int = 0): [User!]!
    post(id: ID!): Post
    posts(limit: Int = 10, offset: Int = 0): [Post!]!
    comment(id: ID!): Comment
    comments(postId: ID, limit: Int = 10, offset: Int = 0): [Comment!]!
  }

  type Mutation {
    createPost(title: String!, content: String!): Post!
    createComment(postId: ID!, content: String!): Comment!
  }
`;

// Input validation utilities
const validateId = (id) => {
  if (!id || typeof id !== 'string' || !/^[a-zA-Z0-9_-]+$/.test(id)) {
    throw new GraphQLError('Invalid ID format', {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }
  return id;
};

const validateString = (str, fieldName, maxLength = 1000) => {
  if (!str || typeof str !== 'string') {
    throw new GraphQLError(`${fieldName} must be a non-empty string`, {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }
  if (str.length > maxLength) {
    throw new GraphQLError(`${fieldName} exceeds maximum length of ${maxLength}`, {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }
  return str.trim();
};

const validatePagination = (limit, offset, maxLimit = 100) => {
  const validLimit = Math.min(Math.max(1, parseInt(limit) || 10), maxLimit);
  const validOffset = Math.max(0, parseInt(offset) || 0);
  return { limit: validLimit, offset: validOffset };
};

// Authentication middleware
const authenticate = (context) => {
  const token = context.token;
  if (!token) {
    throw new GraphQLError('Authentication required', {
      extensions: { code: 'UNAUTHENTICATED' }
    });
  }
  
  // Secure token validation (in production, verify JWT signature)
  const userId = token.replace('Bearer ', '');
  const user = users.find(u => u.id === userId);
  
  if (!user) {
    throw new GraphQLError('Invalid authentication token', {
      extensions: { code: 'UNAUTHENTICATED' }
    });
  }
  
  return user;
};

const resolvers = {
  Query: {
    user: (_, { id }) => {
      validateId(id);
      return users.find(u => u.id === id);
    },
    users: (_, { limit, offset }) => {
      const { limit: validLimit, offset: validOffset } = validatePagination(limit, offset);
      return users.slice(validOffset, validOffset + validLimit);
    },
    post: (_, { id }) => {
      validateId(id);
      return posts.find(p => p.id === id);
    },
    posts: (_, { limit, offset }) => {
      const { limit: validLimit, offset: validOffset } = validatePagination(limit, offset);
      return posts.slice(validOffset, validOffset + validLimit);
    },
    comment: (_, { id }) => {
      validateId(id);
      return comments.find(c => c.id === id);
    },
    comments: (_, { postId, limit, offset }) => {
      if (postId) validateId(postId);
      const { limit: validLimit, offset: validOffset } = validatePagination(limit, offset);
      
      let filtered = postId 
        ? comments.filter(c => c.postId === postId)
        : comments;
      
      return filtered.slice(validOffset, validOffset + validLimit);
    }
  },

  Mutation: {
    createPost: (_, { title, content }, context) => {
      const user = authenticate(context);
      
      const validTitle = validateString(title, 'Title', 200);
      const validContent = validateString(content, 'Content', 5000);
      
      const newPost = {
        id: String(posts.length + 1),
        title: validTitle,
        content: validContent,
        authorId: user.id
      };
      
      posts.push(newPost);
      return newPost;
    },
    
    createComment: (_, { postId, content }, context) => {
      const user = authenticate(context);
      
      validateId(postId);
      const validContent = validateString(content, 'Content', 2000);
      
      const post = posts.find(p => p.id === postId);
      if (!post) {
        throw new GraphQLError('Post not found', {
          extensions: { code: 'NOT_FOUND' }
        });
      }
      
      const newComment = {
        id: String(comments.length + 1),
        content: validContent,
        postId: postId,
        authorId: user.id
      };
      
      comments.push(newComment);
      return newComment;
    }
  },

  User: {
    posts: (user) => {
      return posts.filter(p => p.authorId === user.id);
    },
    comments: (user) => {
      return comments.filter(c => c.authorId === user.id);
    }
  },

  Post: {
    author: (post) => {
      return users.find(u => u.id === post.authorId);
    },
    comments: (post) => {
      return comments.filter(c => c.postId === post.id);
    }
  },

  Comment: {
    post: (comment) => {
      return posts.find(p => p.id === comment.postId);
    },
    author: (comment) => {
      return users.find(u => u.id === comment.authorId);
    }
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  validationRules: [
    depthLimit(7),
    createComplexityLimitRule(1000, {
      onCost: (cost) => {
        console.log('Query cost:', cost);
      }
    })
  ],
  introspection: process.env.NODE_ENV !== 'production',
  csrfPrevention: true,
  cache: 'bounded',
  plugins: [
    {
      async requestDidStart() {
        return {
          async didEncounterErrors(requestContext) {
            // Sanitize error messages in production
            if (process.env.NODE_ENV === 'production') {
              requestContext.errors = requestContext.errors.map(err => {
                if (err.extensions?.code === 'INTERNAL_SERVER_ERROR') {
                  return new GraphQLError('An internal error occurred', {
                    extensions: { code: 'INTERNAL_SERVER_ERROR' }
                  });
                }
                return err;
              });
            }
          }
        };
      }
    }
  ],
  formatError: (formattedError, error) => {
    // Don't expose internal error details
    if (process.env.NODE_ENV === 'production') {
      delete formattedError.extensions?.exception;
      delete formattedError.extensions?.stacktrace;
    }
    return formattedError;
  }
});

startStandaloneServer(server, {
  context: async ({ req }) => {
    const token = req.headers.authorization || '';
    return { token };
  },
  listen: { port: 4000 }
}).then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});